mapper.select:
SELECT t.topic_id, t.forum_id, t.title, t.content, t.user_id, t.last_reply_time, t.view_count, t.reply_count, t.is_pinned, t.status, t.create_time, u.username, u.avatar FROM comm_discussion_topic t LEFT JOIN sys_user u ON t.user_id = u.user_id
t.del_flag = 0
AND t.forum_id = #{forumId}
AND t.title LIKE CONCAT('%', #{title}, '%')
AND t.user_id = #{userId}
AND t.is_pinned = #{isPinned}
ORDER BY t.is_pinned DESC, t.last_reply_time DESC

mapper.update:
UPDATE comm_discussion_topic
SET view_count = view_count + 1
WHERE topic_id = #{topicId}
